1	import { createInterface } from 'readline'
2	
3	/**
4	 * Creates a readline interface for interactive prompts
5	 */
6	function createRl() {
7	  return createInterface({
8	    input: process.stdin,
9	    output: process.stdout,
10	  })
11	}
12	
13	/**
14	 * Ask a question and return the answer
15	 *
16	 * @param {string} question - The prompt text
17	 * @returns {Promise<string>}
18	 */
19	export function ask(question) {
20	  const rl = createRl()
21	  return new Promise((resolve) => {
22	    rl.question(question, (answer) => {
23	      rl.close()
24	      resolve(answer.trim())
25	    })
26	  })
27	}
