29	/**
30	 * Ask user to choose from numbered options
31	 *
32	 * @param {string} prompt - The question text
33	 * @param {Array<string>} options - List of option labels
34	 * @returns {Promise<number>} Selected index (0-based)
35	 */
36	export async function askChoice(prompt, options) {
37	  console.log('')
38	  console.log(prompt)
39	  options.forEach((opt, i) => {
40	    console.log(`  ${i + 1}) ${opt}`)
41	  })
42	
43	  while (true) {
44	    const answer = await ask(`Choice (1-${options.length}): `)
45	    const num = Number.parseInt(answer, 10)
46	    if (num >= 1 && num <= options.length) {
47	      return num - 1
48	    }
49	    console.log(`  Please enter a number between 1 and ${options.length}`)
50	  }
51	}
