53	/**
54	 * Ask yes/no question
55	 *
56	 * @param {string} question - The prompt (y/n will be appended)
57	 * @returns {Promise<boolean>}
58	 */
59	export async function askYesNo(question) {
60	  while (true) {
61	    const answer = await ask(`${question} (y/n): `)
62	    if (answer.toLowerCase() === 'y' || answer.toLowerCase() === 'yes') {
63	      return true
64	    }
65	    if (answer.toLowerCase() === 'n' || answer.toLowerCase() === 'no') {
66	      return false
67	    }
68	    console.log('  Please enter y or n')
69	  }
70	}
