72	/**
73	 * Ask user for multi-line text input (ends with empty line)
74	 *
75	 * @param {string} prompt - The prompt text
76	 * @returns {Promise<string>}
77	 */
78	export async function askMultiLine(prompt) {
79	  console.log(prompt)
